import{c as a,Q as n,j as s,m as e}from"./chunks/framework.Bhbi9jCp.js";const h=JSON.parse('{"title":"客户端渲染管线全貌","description":"","frontmatter":{},"headers":[],"relativePath":"minecraftLearning/20-客户端渲染管线全貌.md","filePath":"minecraftLearning/20-客户端渲染管线全貌.md","lastUpdated":1781676649000}'),o={name:"minecraftLearning/20-客户端渲染管线全貌.md"};function r(i,t,l,p,d,c){return n(),s("div",null,[...t[0]||(t[0]=[e(`<h1 id="客户端渲染管线全貌" tabindex="-1">客户端渲染管线全貌 <a class="header-anchor" href="#客户端渲染管线全貌" aria-label="Permalink to &quot;客户端渲染管线全貌&quot;">​</a></h1><p>第 03 篇讲了一件事:一个 chunk 怎么被合并成一个 mesh、怎么靠面剔除把三角形数量压下来。但那只是&quot;地形几何&quot;这一块。真正按下 F3 看到 60 帧画面时,屏幕上还有水的半透明、树叶的镂空、僵尸的模型、箱子的开盖动画、火把的粒子、明暗渐变的光照——这些都不在 chunk mesh 里,各走各的路径。</p><p>这篇把 chunk 之外的整条管线补上:<strong>一帧到底干了什么,谁在哪条路径上被画出来,以及为什么 Minecraft 的渲染长期是性能瓶颈、Sodium 这类 mod 又重写了什么。</strong></p><blockquote><p>一句话先记住:<strong>Minecraft 的渲染是&quot;把世界拆成几条互不相同的路径,各自剔除、各自排序、各自上色,最后按固定顺序叠到同一帧上&quot;。难点几乎全在两件事——决定&quot;哪些不画&quot;(剔除)和&quot;半透明按什么顺序画&quot;(排序)。</strong></p></blockquote><hr><h2 id="一、两条线程-游戏线程-vs-渲染线程" tabindex="-1">一、两条线程:游戏线程 vs 渲染线程 <a class="header-anchor" href="#一、两条线程-游戏线程-vs-渲染线程" aria-label="Permalink to &quot;一、两条线程:游戏线程 vs 渲染线程&quot;">​</a></h2><p>先破一个常见误解:Minecraft 的&quot;渲染线程&quot;不是一个和游戏逻辑完全并行、各跑各的工人。</p><p>Java 版的真实情况是:</p><ul><li><strong>游戏线程(主线程,Render Thread)</strong>:既跑客户端逻辑,也发 OpenGL 绘制调用。它是那条按帧循环、最终提交 draw call 的线程。</li><li><strong>集成服务端线程(Server Thread)</strong>:单机时世界逻辑(第 04 篇那套 20 TPS tick)跑在另一条线程,通过内存管道和客户端通信。</li><li><strong>工作线程池</strong>:chunk 的 mesh 构建(第 03 篇那套&quot;遍历方块、生成可见面&quot;)被甩到后台线程池里异步做,做完把顶点数据交回主线程上传 GPU。</li></ul><p>所以&quot;帧率&quot;和&quot;TPS&quot;是两套时钟(第 04 篇已强调):</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Server Thread:  ──tick──tick──tick──   固定 20 次/秒,管世界状态</span></span>
<span class="line"><span>                        │ 状态快照 / 实体位置</span></span>
<span class="line"><span>                        ▼</span></span>
<span class="line"><span>Render Thread:  ─帧─帧─帧─帧─帧─帧─帧─   能多快多快,管&quot;把当前状态画出来&quot;</span></span>
<span class="line"><span>                  ▲</span></span>
<span class="line"><span>        Worker Pool: 后台重建脏 chunk 的 mesh,不卡帧</span></span></code></pre></div><p><strong>反直觉点</strong>:实体位置每秒只更新 20 次,但你看到的移动是丝滑的——因为渲染帧之间客户端对实体做<strong>插值</strong>(下面讲)。世界状态是&quot;阶梯&quot;,画面是&quot;插出来的斜坡&quot;。</p><hr><h2 id="二、一帧里发生什么" tabindex="-1">二、一帧里发生什么 <a class="header-anchor" href="#二、一帧里发生什么" aria-label="Permalink to &quot;二、一帧里发生什么&quot;">​</a></h2><p>按顺序拆一帧(简化但保真):</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. 处理输入、推进摄像机(含 partialTick 插值因子)</span></span>
<span class="line"><span>2. 更新区块可见性:从摄像机所在 section 做 BFS,标记哪些 render section 要画</span></span>
<span class="line"><span>3. 地形几何:按 RenderType 分批,画所有可见 render section 的已上传 mesh</span></span>
<span class="line"><span>     ├─ solid       不透明</span></span>
<span class="line"><span>     ├─ cutout      镂空(树叶、草、铁栏杆)</span></span>
<span class="line"><span>     └─ translucent 半透明(水、玻璃、冰)—— 需按距离排序</span></span>
<span class="line"><span>4. 实体:遍历附近实体,各自的 EntityRenderer 画模型</span></span>
<span class="line"><span>5. 方块实体:BlockEntityRenderer 画箱子盖、告示牌字、床、信标光柱</span></span>
<span class="line"><span>6. 粒子:烟、火、药水雾(纯客户端)</span></span>
<span class="line"><span>7. 天空盒、云、天气、debug 线框(F3 的 chunk 边界)</span></span>
<span class="line"><span>8. 半透明的二次处理、手部模型、HUD/GUI</span></span>
<span class="line"><span>9. 提交帧</span></span></code></pre></div><p>注意第 1 步那个 <strong>partialTick</strong>:它是&quot;距离上一个游戏 tick 过去了百分之几&quot;的小数。所有平滑动画——摄像机、实体、箱子盖角度——都是拿上一 tick 和这一 tick 的值,用 partialTick 线性插值出&quot;此刻该显示的中间态&quot;。这是 20 TPS 的世界能渲染出任意高帧率的根本机制。</p><hr><h2 id="三、rendertype-为什么世界要拆成几批画" tabindex="-1">三、RenderType:为什么世界要拆成几批画 <a class="header-anchor" href="#三、rendertype-为什么世界要拆成几批画" aria-label="Permalink to &quot;三、RenderType:为什么世界要拆成几批画&quot;">​</a></h2><p>不能&quot;一个方块一个方块按出现顺序画&quot;。GPU 喜欢&quot;同一种材质/混合模式的东西连着画&quot;,而且<strong>半透明必须在不透明之后、且从远到近</strong>才正确。所以地形几何按 <strong>RenderType</strong> 分桶:</p><table tabindex="0"><thead><tr><th>RenderType</th><th>典型方块</th><th>关键特性</th><th>难点</th></tr></thead><tbody><tr><td><code>solid</code></td><td>石头、泥土</td><td>完全不透明,深度测试直接挡</td><td>最简单,顺序无所谓</td></tr><tr><td><code>cutout</code></td><td>树叶、草、铁栏杆</td><td>像素要么全不透明要么全透明(alpha 测试丢弃透明像素)</td><td>边缘锯齿;<code>cutout_mipped</code> 处理 mipmap</td></tr><tr><td><code>translucent</code></td><td>水、玻璃、冰、染色玻璃</td><td>半透明,要 alpha 混合</td><td><strong>必须从远到近排序</strong>,否则混合结果错</td></tr></tbody></table><p><strong>translucent 为什么是老大难</strong>:半透明像素的颜色是&quot;自己的色 × alpha + 背后已有的色 × (1-alpha)&quot;。这要求背后的东西<strong>先画好</strong>。两块玻璃前后叠着,先画近的再画远的,远的那块就会被近的错误地&quot;挡掉一部分混合&quot;。所以每个 render section 内部的半透明三角形要<strong>按到摄像机距离排序</strong>,而且摄像机一移动,排序可能失效需要重排——这是开 shader/大量水面时掉帧的常见来源。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>不透明:谁先画无所谓,深度缓冲自动挡住后面的</span></span>
<span class="line"><span>半透明:必须 远 → 近,逐层混合</span></span>
<span class="line"><span>        画错顺序 → 玻璃后面的玻璃&quot;消失&quot;或发黑</span></span></code></pre></div><hr><h2 id="四、render-section-与-gpu-上传" tabindex="-1">四、render section 与 GPU 上传 <a class="header-anchor" href="#四、render-section-与-gpu-上传" aria-label="Permalink to &quot;四、render section 与 GPU 上传&quot;">​</a></h2><p>接第 03 篇:世界按 16×16×16 切成 <strong>render section</strong>(渲染区段,和存储的 section 对齐)。每个 render section 维护<strong>每种 RenderType 一个 mesh</strong>。</p><p>生命周期:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>方块改动 → 该 section 标记 dirty</span></span>
<span class="line"><span>       → 丢进 worker pool 重建 mesh(遍历方块、生成可见面、按 RenderType 分桶)</span></span>
<span class="line"><span>       → 顶点数据上传到 GPU 的 VBO</span></span>
<span class="line"><span>       → 主线程渲染时,对可见 section 直接发&quot;画这块 VBO&quot;</span></span></code></pre></div><p>要点:</p><ul><li><strong>改一格只重建一个 section</strong>(第 03 篇说过),但如果改在边界,相邻 section 的剔除也变了,会连带重建邻居。</li><li>原版用 per-section 的小 VBO,<strong>draw call 数量 = 可见 section 数 × 用到的 RenderType 数</strong>,几百上千个 draw call。这正是性能瓶颈所在。</li><li><strong>Sodium 的核心优化之一</strong>就是把这些零碎 VBO 合并、用更现代的 OpenGL(持久映射缓冲、间接绘制、把剔除搬到 GPU),把成百上千 draw call 压成个位数。后面再说。</li></ul><hr><h2 id="五、剔除-整条管线最值钱的-不画" tabindex="-1">五、剔除:整条管线最值钱的&quot;不画&quot; <a class="header-anchor" href="#五、剔除-整条管线最值钱的-不画" aria-label="Permalink to &quot;五、剔除:整条管线最值钱的&quot;不画&quot;&quot;">​</a></h2><p>画得快的第一性原理是<strong>少画</strong>。Minecraft 用两层剔除决定&quot;哪些 render section 根本不提交&quot;:</p><h3 id="_1-视锥剔除-frustum-culling" tabindex="-1">1. 视锥剔除(frustum culling) <a class="header-anchor" href="#_1-视锥剔除-frustum-culling" aria-label="Permalink to &quot;1. 视锥剔除(frustum culling)&quot;">​</a></h3><p>摄像机的可视范围是一个四棱锥(frustum)。section 的包围盒完全在锥外 → 直接跳过。这是便宜且通用的第一道关:背后的、视野外的世界不画。</p><h3 id="_2-区块可见性遍历-cave-culling" tabindex="-1">2. 区块可见性遍历(cave culling) <a class="header-anchor" href="#_2-区块可见性遍历-cave-culling" aria-label="Permalink to &quot;2. 区块可见性遍历(cave culling)&quot;">​</a></h3><p>这是 Minecraft 特有、也最聪明的一招,专治&quot;在洞穴/室内时不想画身后整片地下世界&quot;:</p><p>预处理时,给每个 section 算一张**&quot;从哪个面进、能从哪个面出&quot;的连通表**(光/视线能否穿过这个 section 内部的空气连通区)。渲染时<strong>从摄像机所在 section 出发做 BFS</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>站在洞里:</span></span>
<span class="line"><span>  当前 section → 看它六个面哪些&quot;通&quot;(内部有空气连到该面)</span></span>
<span class="line"><span>  只沿&quot;通&quot;的面扩散到邻居,且记录进入方向避免回头穿实心</span></span>
<span class="line"><span>  → 被实心岩石包住的 section 永远扩散不到 → 不画</span></span></code></pre></div><p>效果:在地下或建筑里,身后被墙挡住的几千个 section 根本不进渲染列表。<strong>反直觉的副作用</strong>:F3 里能看到&quot;被挡住的区块不渲染&quot;,偶尔卡视角会看到世界&quot;漏洞&quot;——那就是 cave culling 判断你看不到、于是没画。</p><p>两层叠加:frustum 砍掉视野外,cave culling 砍掉视野内但被实体方块挡死的。剩下的才上传 draw call。</p><hr><h2 id="六、实体、方块实体、粒子-各走各的路" tabindex="-1">六、实体、方块实体、粒子:各走各的路 <a class="header-anchor" href="#六、实体、方块实体、粒子-各走各的路" aria-label="Permalink to &quot;六、实体、方块实体、粒子:各走各的路&quot;">​</a></h2><p>地形是&quot;静态批量几何&quot;,但会动的东西不能塞进 chunk mesh(它们每帧位置/姿态都变),所以走独立路径:</p><table tabindex="0"><thead><tr><th>类别</th><th>渲染器</th><th>特点</th></tr></thead><tbody><tr><td>实体(第 06 篇)</td><td><code>EntityRenderer</code></td><td>每帧按插值后的位置/朝向画模型、骨骼动画、装备叠加</td></tr><tr><td>方块实体(第 09 篇)</td><td><code>BlockEntityRenderer</code></td><td>给&quot;标准方块模型画不出来的&quot;方块做特殊绘制</td></tr><tr><td>粒子(第 10 篇)</td><td>粒子引擎</td><td>纯客户端,面向摄像机的小四边形(billboard)</td></tr></tbody></table><p><strong>方块实体渲染器</strong>正好接上第 09 篇的核心结论:床、箱子之所以是方块实体,很大程度就是为了挂这个渲染器。箱子盖的开合角度由 <code>ChestLidController</code> 维护一个 0~1 的值,<strong>每帧用 partialTick 插值</strong>出当前角度再画——所以盖子是平滑掀开而不是瞬间跳。大箱子还要靠 <code>DoubleBlockCombiner</code> 把两半的盖子同步绘制成一个连续模型。这些都不可能用静态 chunk mesh 表达,只能逐帧重画。</p><p>代价:方块实体渲染器是<strong>逐个、每帧、在主线程</strong>跑的。一屏几百个告示牌/箱子(尤其大型仓库)会明显掉帧——这和第 04 篇&quot;方块实体每 tick 遍历很贵&quot;是同一类问题的渲染版。</p><hr><h2 id="七、光照表现-逐格-0-15-怎么变成丝滑明暗" tabindex="-1">七、光照表现:逐格 0-15 怎么变成丝滑明暗 <a class="header-anchor" href="#七、光照表现-逐格-0-15-怎么变成丝滑明暗" aria-label="Permalink to &quot;七、光照表现:逐格 0-15 怎么变成丝滑明暗&quot;">​</a></h2><p>第 10 篇讲了光照是<strong>逐格、两通道(BlockLight + SkyLight)、0~15</strong> 的数据层。渲染端要把这些离散整数变成画面上的连续明暗,靠两个机制:</p><h3 id="_1-lightmap-光照贴图" tabindex="-1">1. lightmap(光照贴图) <a class="header-anchor" href="#_1-lightmap-光照贴图" aria-label="Permalink to &quot;1. lightmap(光照贴图)&quot;">​</a></h3><p>把 <code>(blockLight, skyLight)</code> 这对 0~15 的值当成一张 16×16 查找纹理的坐标,采样出一个最终颜色乘子。这张 lightmap 还随时间(白天/黑夜让 skyLight 列变暗)、随维度(下界偏红)、随药水(夜视拉亮)整体重算。所以&quot;日落时世界慢慢变暗&quot;不是逐方块改光照值,而是<strong>lightmap 这张表在变</strong>。</p><h3 id="_2-平滑光照-环境光遮蔽-ao" tabindex="-1">2. 平滑光照 / 环境光遮蔽(AO) <a class="header-anchor" href="#_2-平滑光照-环境光遮蔽-ao" aria-label="Permalink to &quot;2. 平滑光照 / 环境光遮蔽(AO)&quot;">​</a></h3><p>如果每个方块面直接取自己那格的光照值,你会看到生硬的块状明暗。平滑光照(Smooth Lighting)在<strong>生成 mesh 时</strong>,给每个顶点取<strong>周围四格光照的平均</strong>,再让 GPU 在面内插值,于是明暗是渐变的。AO(环境光遮蔽)再额外压暗凹角(被三个方块围住的顶点更暗),给体素世界一点立体感。</p><p><strong>反直觉点</strong>:平滑光照是 chunk meshing 阶段的逐顶点计算,<strong>烤进顶点数据</strong>里。所以光照一变(放火把),不只是改数据,还要<strong>重建受影响 section 的 mesh</strong>——这就是为什么放一个火把会让周围一圈 chunk 短暂重建,也是光照成为性能热点(第 19 篇会展开)、Starlight 重写光照引擎的原因之一。</p><hr><h2 id="八、f3-把这条管线掀开给你看" tabindex="-1">八、F3:把这条管线掀开给你看 <a class="header-anchor" href="#八、f3-把这条管线掀开给你看" aria-label="Permalink to &quot;八、F3:把这条管线掀开给你看&quot;">​</a></h2><p>F3 调试屏其实是这条管线的仪表盘:</p><ul><li><strong>C: xxx/yyy</strong> —— 渲染了多少 section / 总共多少(看 cave culling + frustum 砍掉了多少)</li><li><strong>E: a+b</strong> —— 实体渲染数 / tick 数</li><li><strong>chunk 边界(F3+G)</strong> —— 画出 section 网格,直接看到&quot;渲染区段&quot;的切分</li><li><strong>fps 与 &quot;without/with vsync&quot;</strong> —— 帧率;和左下的内存、右侧的方块/光照数据一起,能定位是&quot;画太多&quot;还是&quot;逻辑卡&quot;</li></ul><p>学会读 C 那行尤其有用:在洞里它远小于平地,就是 cave culling 在干活。</p><hr><h2 id="九、为什么原版渲染慢-sodium-改了什么" tabindex="-1">九、为什么原版渲染慢,Sodium 改了什么 <a class="header-anchor" href="#九、为什么原版渲染慢-sodium-改了什么" aria-label="Permalink to &quot;九、为什么原版渲染慢,Sodium 改了什么&quot;">​</a></h2><p>原版渲染的结构性问题,基本都在前面埋着:</p><table tabindex="0"><thead><tr><th>问题</th><th>根因</th><th>Sodium 的做法</th></tr></thead><tbody><tr><td>draw call 太多</td><td>每 section 每 RenderType 一个小 VBO</td><td>合并缓冲、批量/间接绘制,几个 draw call 搞定</td></tr><tr><td>剔除在 CPU 上</td><td>主线程逐 section 判可见</td><td>把剔除/排序往 GPU 和并行挪</td></tr><tr><td>用老旧 OpenGL</td><td>历史包袱</td><td>现代 GL(持久映射、VAO、更紧凑顶点格式)</td></tr><tr><td>半透明排序卡</td><td>CPU 逐三角排序</td><td>更高效的排序与缓存</td></tr></tbody></table><p><strong>结论性的话</strong>:Sodium 没有改&quot;世界是什么&quot;(数据模型一字没动),它只改了&quot;怎么把同样的世界喂给 GPU&quot;——把第三~五节那套 RenderType 分桶、VBO 上传、CPU 剔除,换成对现代显卡友好的组织方式。这也说明原版的瓶颈不在显卡算力,而在<strong>提交方式</strong>。</p><hr><h2 id="串起来" tabindex="-1">串起来 <a class="header-anchor" href="#串起来" aria-label="Permalink to &quot;串起来&quot;">​</a></h2><p>这一篇补全了第 03 篇之后的半张图:</p><ul><li>第 03 篇:<strong>一个 chunk 的几何</strong>怎么生成(面剔除、mesh 合并)。</li><li>本篇:这块几何之外,<strong>整帧怎么组织</strong>——两线程分工 + partialTick 插值让 20 TPS 世界跑出高帧;地形按 RenderType 分桶、半透明排序;两层剔除(frustum + cave culling)决定&quot;不画什么&quot;;实体/方块实体/粒子各走独立逐帧路径;光照靠 lightmap + 平滑光照把离散 0-15 变成渐变明暗。</li></ul><p>往后:第 19 篇会把这里反复出现的&quot;光照重建、方块实体逐帧、draw call 过多&quot;收进一篇<strong>性能诊断</strong>,讲怎么用 profiler 定位、Lithium/Starlight/Sodium/C2ME 各治哪一段。一句话收口:<strong>渲染的快慢,九成是&quot;不画什么&quot;和&quot;按什么顺序画&quot;决定的,剩下一成才是怎么把要画的高效喂给 GPU。</strong></p>`,70)])])}const g=a(o,[["render",r]]);export{h as __pageData,g as default};
